import React, { useState, useMemo } from 'react';
import { 
  Calendar, 
  AlertTriangle, 
  Download, 
  Edit2, 
  Check, 
  X,
  LayoutGrid,
  List,
  Search,
  Trash2,
  MessageSquare,
  Copy,
  ArrowRightLeft,
  Clock,
  User,
  PlusCircle,
  ChevronLeft,
  ChevronRight,
  Map,
  Briefcase,
  Users,
  Filter as FilterIcon,
  Database,
  Upload,
  UserPlus,
  Save
} from 'lucide-react';

// --- UTILITÁRIOS DE DATA ---
const formatDate = (dateStr) => {
  if (!dateStr) return '-';
  const [year, month, day] = dateStr.split('-');
  return `${day}/${month}/${year}`;
};

const addDays = (dateStr, days) => {
  if (!dateStr) return '';
  const date = new Date(dateStr + 'T12:00:00');
  date.setDate(date.getDate() + days);
  return date.toISOString().split('T')[0];
};

const getReturnDate = (dateStr, days) => {
    return addDays(dateStr, days + 1); 
};

// --- BASE DE DADOS INICIAL ---
const INITIAL_DB = [
  { 
    id: 924, name: 'MARCIA MILENA SOUZA CORREA', city: 'SINOP - MT', role: 'COORD EVERTON', regional: 'CENTRO OESTE', admission: '2009-03-02', limitDate: '2026-02-02', balance: 0, status: 'vencido', 
    period1: { start: null, duration: 0 }, period2: { start: null, duration: 0 }
  },
  { 
    id: 5926, name: 'LIVIA ESTER ANDRADE DOS SANTOS', city: 'GOIANIA - GO', role: 'COORD EVERTON', regional: 'CENTRO OESTE', admission: '2021-04-20', limitDate: '2026-03-20', balance: 0, status: 'negociacao', 
    period1: { start: null, duration: 0 }, period2: { start: null, duration: 0 }
  },
  { 
    id: 754, name: 'FRANCISCA KATIA IRENE', city: 'TERESINA - PI', role: 'LIDER EVERTON', regional: 'NORDESTE', admission: '2018-05-10', limitDate: '2026-05-10', balance: 15, status: 'confirmado', 
    period1: { start: '2026-04-07', duration: 15 }, period2: { start: null, duration: 0 } 
  },
  { 
    id: 5905, name: 'DIEGO PAES DE PAULA', city: 'SAO PAULO - SP', role: 'LIDER DIEGO', regional: 'SÃO PAULO', admission: '2020-01-15', limitDate: '2026-06-15', balance: 15, status: 'confirmado', 
    period1: { start: '2026-06-04', duration: 15 }, period2: { start: null, duration: 0 } 
  },
  { 
    id: 6096, name: 'ITALO BERNARDO DA SILVA', city: 'RIBEIRAO PRETO - SP', role: 'LIDER EVERTON', regional: 'SÃO PAULO', admission: '2023-09-23', limitDate: '2026-08-23', balance: 30, status: 'vencido', 
    period1: { start: null, duration: 0 }, period2: { start: null, duration: 0 } 
  },
  { 
    id: 6100, name: 'JACKSON PEREIRA AUGUSTO', city: 'GUARULHOS - SP', role: 'LIDER DIEGO', regional: 'SÃO PAULO', admission: '2023-09-23', limitDate: '2026-08-23', balance: 30, status: 'avencer', 
    period1: { start: null, duration: 0 }, period2: { start: null, duration: 0 } 
  },
];

const StatusBadge = ({ status }) => {
  const config = {
    confirmado: { color: 'bg-green-100 text-green-800 border-green-200', label: 'Confirmado' },
    negociacao: { color: 'bg-yellow-100 text-yellow-800 border-yellow-200', label: 'Em Negociação' },
    vencido: { color: 'bg-red-100 text-red-800 border-red-200', label: 'Vencido' },
    avencer: { color: 'bg-blue-50 text-blue-600 border-blue-100', label: 'A Vencer' },
  };
  const style = config[status] || config.avencer;

  return (
    <span className={`text-[10px] uppercase font-bold px-2 py-0.5 rounded border ${style.color}`}>
      {style.label}
    </span>
  );
};

export default function JuncoHub() {
  const [currentView, setCurrentView] = useState('dashboard');
  const [promoters, setPromoters] = useState(INITIAL_DB);
  const [searchTerm, setSearchTerm] = useState('');
  
  // FILTROS AVANÇADOS
  const [showFilters, setShowFilters] = useState(false);
  const [columnFilters, setColumnFilters] = useState({
    promotor: '',
    balance: '',
    status: '',
    limitDate: ''
  });
  
  // Estado do Calendário
  const [calendarDate, setCalendarDate] = useState(new Date('2026-01-01T12:00:00')); 

  // Edição e Modais
  const [editingPromoterId, setEditingPromoterId] = useState(null);
  const [editFormData, setEditFormData] = useState({});
  const [isScheduleModalOpen, setIsScheduleModalOpen] = useState(false);
  const [isCommModalOpen, setIsCommModalOpen] = useState(false);
  const [isAddModalOpen, setIsAddModalOpen] = useState(false); // Novo Modal de Adicionar
  const [commType, setCommType] = useState('confirmacao'); 
  const [targetPeriod, setTargetPeriod] = useState('both'); 
  const [selectedPromoter, setSelectedPromoter] = useState(null);
  const [scheduleForm, setScheduleForm] = useState({ startDate: '', duration: 15 });
  const [scheduleError, setScheduleError] = useState(null);
  
  const [selectedLeader, setSelectedLeader] = useState(null);

  // --- LÓGICA DE AGRUPAMENTO (DASHBOARD) ---
  const statsByRegional = useMemo(() => {
    const acc = {};
    promoters.forEach(p => {
        const reg = p.regional || 'OUTROS';
        if (!acc[reg]) acc[reg] = { total: 0, vencido: 0, negociacao: 0, confirmado: 0 };
        acc[reg].total++;
        if (p.status === 'vencido') acc[reg].vencido++;
        if (p.status === 'negociacao') acc[reg].negociacao++;
        if (p.status === 'confirmado') acc[reg].confirmado++;
    });
    return Object.entries(acc);
  }, [promoters]);

  const statsByLeader = useMemo(() => {
    const acc = {};
    promoters.forEach(p => {
        const role = p.role || 'SEM LÍDER';
        if (!acc[role]) acc[role] = { total: 0, vencido: 0, negociacao: 0, confirmado: 0 };
        acc[role].total++;
        if (p.status === 'vencido') acc[role].vencido++;
        if (p.status === 'negociacao') acc[role].negociacao++;
        if (p.status === 'confirmado') acc[role].confirmado++;
    });
    return Object.entries(acc);
  }, [promoters]);

  // --- LÓGICA DO CALENDÁRIO DINÂMICO ---
  const handlePrevMonth = () => {
    setCalendarDate(new Date(calendarDate.getFullYear(), calendarDate.getMonth() - 1, 1));
  };

  const handleNextMonth = () => {
    setCalendarDate(new Date(calendarDate.getFullYear(), calendarDate.getMonth() + 1, 1));
  };

  const monthNames = ["Janeiro", "Fevereiro", "Março", "Abril", "Maio", "Junho", "Julho", "Agosto", "Setembro", "Outubro", "Novembro", "Dezembro"];

  // --- EXPORTAÇÃO CSV (GESTÃO DE FÉRIAS) ---
  const handleExportCSV = () => {
    const header = ["Cód.Func", "Funcionário", "Cidade", "Hieraequia", "Dt.Saida", "Dt.Retorno"];
    const rows = [];

    promoters.forEach(p => {
        if (p.period1.start) {
            rows.push([p.id, p.name, p.city, p.role, formatDate(p.period1.start), formatDate(getReturnDate(p.period1.start, p.period1.duration))]);
        }
        if (p.period2.start) {
            rows.push([p.id, p.name, p.city, p.role, formatDate(p.period2.start), formatDate(getReturnDate(p.period2.start, p.period2.duration))]);
        }
    });

    if (rows.length === 0) { alert("Não há férias confirmadas para exportar."); return; }

    const csvContent = "\uFEFF" + [header.join(";"), ...rows.map(row => row.map(item => `"${item}"`).join(";"))].join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", "Resumo_Ferias_Junco.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- EXPORTAÇÃO CSV (BASE COMPLETA) - NOVA FUNÇÃO ---
  const handleExportBaseCSV = () => {
    const header = ["ID", "Nome", "Cidade", "Regional", "Cargo", "Admissão", "Data Limite", "Saldo Dias", "Status"];
    const rows = promoters.map(p => [
        p.id,
        p.name,
        p.city,
        p.regional,
        p.role,
        formatDate(p.admission),
        formatDate(p.limitDate),
        p.balance,
        p.status
    ]);

    if (rows.length === 0) {
        alert("Base de dados vazia.");
        return;
    }

    // Padrão Ponto e Vírgula (Excel Brasil) + BOM para acentuação
    const csvContent = "\uFEFF" + [
        header.join(";"),
        ...rows.map(row => row.map(item => `"${item}"`).join(";"))
    ].join("\n");

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", "Base_Completa_Promotores.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- LÓGICA DE FILTRAGEM (ATUALIZADA) ---
  const filteredPromoters = useMemo(() => {
    return promoters.filter(p => {
      const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase()) || p.city.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesPromotor = columnFilters.promotor === '' || p.name.toLowerCase().includes(columnFilters.promotor.toLowerCase()) || p.city.toLowerCase().includes(columnFilters.promotor.toLowerCase());
      const matchesBalance = columnFilters.balance === '' || p.balance.toString() === columnFilters.balance;
      const matchesStatus = columnFilters.status === '' || p.status === columnFilters.status;
      const matchesLimit = columnFilters.limitDate === '' || formatDate(p.limitDate).includes(columnFilters.limitDate);
      return matchesSearch && matchesPromotor && matchesBalance && matchesStatus && matchesLimit;
    });
  }, [promoters, searchTerm, columnFilters]);

  const kpis = {
    vencidos: promoters.filter(p => p.status === 'vencido').length,
    negociacao: promoters.filter(p => p.status === 'negociacao').length,
    confirmados: promoters.filter(p => p.status === 'confirmado').length,
  };

  const toggleNegotiationStatus = (promoter) => {
    const newStatus = promoter.status === 'vencido' ? 'negociacao' : 'vencido';
    setPromoters(promoters.map(p => p.id === promoter.id ? { ...p, status: newStatus } : p));
  };

  // --- CRUD BASE DE DADOS ---
  const handleAddNew = (newData) => {
      const newId = Math.max(...promoters.map(p => p.id)) + 1;
      const newPromoter = {
          id: newId,
          ...newData,
          period1: { start: null, duration: 0 },
          period2: { start: null, duration: 0 }
      };
      setPromoters([...promoters, newPromoter]);
      setIsAddModalOpen(false);
  };

  const handleDeletePromoter = (id) => {
      if(window.confirm("Tem certeza que deseja excluir este promotor da base?")){
          setPromoters(promoters.filter(p => p.id !== id));
      }
  };

  const handleStartEdit = (promoter) => { setEditingPromoterId(promoter.id); setEditFormData({ ...promoter }); };
  const handleSaveEdit = () => { 
      setPromoters(promoters.map(p => p.id === editingPromoterId ? { ...editFormData } : p)); 
      setEditingPromoterId(null); 
  };

  // --- AGENDAMENTO E COMUNICAÇÃO ---
  const handleOpenSchedule = (promoter) => {
    setSelectedPromoter(promoter);
    const suggestion = promoter.balance > 15 ? 15 : promoter.balance;
    setScheduleForm({ startDate: '', duration: suggestion });
    setScheduleError(null);
    setIsScheduleModalOpen(true);
  };

  const validateAndSaveSchedule = () => {
    if (!scheduleForm.startDate) { setScheduleError("Selecione uma data."); return; }
    if (scheduleForm.duration <= 0) { setScheduleError("Duração inválida."); return; }
    if (scheduleForm.duration > selectedPromoter.balance) { setScheduleError(`Erro: O promotor tem apenas ${selectedPromoter.balance} dias de saldo.`); return; }

    const startStr = scheduleForm.startDate;
    const endStr = addDays(startStr, scheduleForm.duration);
    
    // Regra Dia da Semana
    const start = new Date(startStr + 'T12:00:00');
    const dayOfWeek = start.getDay(); 
    if (dayOfWeek !== 1 && dayOfWeek !== 2) { setScheduleError("⚠️ Início permitido apenas às Segundas ou Terças-feiras."); return; }

    // Regra Conflito Praça
    const conflict = promoters.find(p => {
      if (p.id === selectedPromoter.id || p.city !== selectedPromoter.city || p.status !== 'confirmado') return false;
      const checkCollision = (pStart, pDur) => { if(!pStart) return false; const pEnd = addDays(pStart, pDur); return (startStr <= pEnd && endStr >= pStart); };
      return checkCollision(p.period1.start, p.period1.duration) || checkCollision(p.period2.start, p.period2.duration);
    });
    if (conflict) { setScheduleError(`⛔ Conflito: ${conflict.name} já estará de férias em ${selectedPromoter.city} neste período.`); return; }

    // Regra Conflito Próprio
    const p1 = selectedPromoter.period1;
    const p2 = selectedPromoter.period2;
    let otherPeriod = !p1.start ? p2 : p1; // Se P1 vazio, verifica P2 (se houver). Se P1 cheio, verifica P1.

    if (otherPeriod && otherPeriod.start) {
        const otherStart = new Date(otherPeriod.start + 'T12:00:00');
        const otherEnd = new Date(addDays(otherPeriod.start, otherPeriod.duration) + 'T12:00:00');
        const newStart = new Date(startStr + 'T12:00:00');
        const newEnd = new Date(endStr + 'T12:00:00');

        if (newStart <= otherEnd && newEnd >= otherStart) { setScheduleError(`⛔ Erro: Data coincide com o outro período já marcado.`); return; }
        
        const diffMonths = (newStart.getFullYear() - otherStart.getFullYear()) * 12 + (newStart.getMonth() - otherStart.getMonth());
        if (Math.abs(diffMonths) < 2) { setScheduleError(`⛔ Regra de Intervalo: Férias não podem ser em meses consecutivos.`); return; }
    }

    setPromoters(promoters.map(p => {
      if (p.id === selectedPromoter.id) {
          const newP = { ...p, status: 'confirmado', balance: p.balance - scheduleForm.duration };
          if (!p.period1.start) newP.period1 = { start: startStr, duration: scheduleForm.duration };
          else newP.period2 = { start: startStr, duration: scheduleForm.duration };
          return newP;
      }
      return p;
    }));
    setIsScheduleModalOpen(false);
  };

  const handleOpenComm = (promoter) => {
    setSelectedPromoter(promoter);
    const hasP1 = !!promoter.period1.start;
    const hasP2 = !!promoter.period2.start;
    if (hasP1 && hasP2) setTargetPeriod('both'); else if (hasP1) setTargetPeriod('p1'); else if (hasP2) setTargetPeriod('p2'); else setTargetPeriod('none');
    if (promoter.status === 'vencido' || promoter.status === 'negociacao') setCommType('comercial'); else setCommType('confirmacao');
    setIsCommModalOpen(true);
  };

  const generateMessage = () => {
    if (!selectedPromoter) return '';
    const p1 = selectedPromoter.period1;
    const p2 = selectedPromoter.period2;
    const includeP1 = (targetPeriod === 'p1' || targetPeriod === 'both') && !!p1.start;
    const includeP2 = (targetPeriod === 'p2' || targetPeriod === 'both') && !!p2.start;

    if (commType === 'comercial') {
        return `Boa dia time, tudo bem?\n\nEstamos com um promotor que está com férias vencidas e precisamos marcar-las, Segue abaixo o promotor!\n\n*${selectedPromoter.name}*\n${selectedPromoter.city}\n\nLembrando que ele goza das férias apenas em períodos de 15 dias, sendo necessário marcar apenas *UM* período por conta das férias coletivas.`;
    }
    if (commType === 'confirmacao') {
        let text = "";
        if (includeP1) text += `*Primeiro Período:*\n*Início:* ${formatDate(p1.start)}\n*Termino:* ${formatDate(addDays(p1.start, p1.duration))}\n*Retorno:* _${formatDate(getReturnDate(p1.start, p1.duration))}_\n\n`;
        if (includeP2) text += `*Segundo Período:*\n*Início:* ${formatDate(p2.start)}\n*Termino:* ${formatDate(addDays(p2.start, p2.duration))}\n*Retorno:* _${formatDate(getReturnDate(p2.start, p2.duration))}_`;
        if (!text) return "Selecione um período.";
        return `🤖*MENSAGEM AUTOMÁTICA*🤖\n\nCaro(a) colaborador(a), seus períodos de férias foram agendados com sucesso para as seguintes datas:\n\n${text}\n\nPara acompanhar, basta acessar o aplicativo *_Pessoas+_*`;
    }
    const activeStart = includeP1 ? p1.start : (includeP2 ? p2.start : null);
    const activeDur = includeP1 ? p1.duration : (includeP2 ? p2.duration : 0);
    if (!activeStart) return "Selecione um período agendado.";
    
    if (commType === 'lembrete') return `Prezado,\n\nGostaríamos de informar que suas férias se iniciam no dia ${formatDate(activeStart)} e seu retorno às atividades será no dia ${formatDate(getReturnDate(activeStart, activeDur))}.\n\nDesejamos boas férias!`;
    if (commType === 'lideranca') return `Bom dia time, tudo bem?\n\nGostaríamos de informar que o promotor *${selectedPromoter.name}* (${selectedPromoter.city}) entrará em férias em breve.\n\n*Início:* ${formatDate(activeStart)}\n*Retorno:* ${formatDate(getReturnDate(activeStart, activeDur))}\n\nFavor se atentarem a este período.`;
    return '';
  };

  const handleDeleteVacation = (id) => {
    if(window.confirm("Isso cancelará TODOS os agendamentos deste promotor. Confirmar?")){
        setPromoters(promoters.map(p => p.id === id ? { ...p, status: 'negociacao', period1: {start: null, duration: 0}, period2: {start: null, duration: 0}, balance: 30 } : p));
    }
  };

  // --- MODAIS RENDER ---
  const LeaderDetailsModal = () => {
    if (!selectedLeader) return null;
    const leaderPromoters = promoters.filter(p => p.role === selectedLeader);
    const onVacation = leaderPromoters.filter(p => p.status === 'confirmado');
    const others = leaderPromoters.filter(p => p.status !== 'confirmado');

    return (
      <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
        <div className="bg-white rounded-xl shadow-xl w-full max-w-2xl max-h-[85vh] flex flex-col">
            <div className="p-4 border-b flex justify-between items-center bg-gray-50 rounded-t-xl shrink-0"><h3 className="font-bold text-gray-800">{selectedLeader}</h3><button onClick={() => setSelectedLeader(null)}><X size={20}/></button></div>
            <div className="p-6 overflow-y-auto custom-scrollbar">
                <h4 className="text-xs font-bold text-gray-500 uppercase mb-3">Em Férias / Agendados ({onVacation.length})</h4>
                <div className="space-y-2 mb-6">{onVacation.map(p => (<div key={p.id} className="flex justify-between p-3 bg-green-50 border border-green-100 rounded-lg"><div className="text-sm font-bold">{p.name}</div><div className="text-xs">{formatDate(p.period1.start || p.period2.start)}</div></div>))}</div>
                <h4 className="text-xs font-bold text-gray-500 uppercase mb-3">Pendências ({others.length})</h4>
                <div className="space-y-2">{others.map(p => (<div key={p.id} className="flex justify-between p-3 border rounded-lg"><div className="text-sm">{p.name}</div><StatusBadge status={p.status}/></div>))}</div>
            </div>
        </div>
      </div>
    );
  };

  const CommunicationModal = () => {
    if (!isCommModalOpen || !selectedPromoter) return null;
    const message = generateMessage();
    const hasP1 = !!selectedPromoter.period1.start;
    const hasP2 = !!selectedPromoter.period2.start;

    return (
      <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
        <div className="bg-white rounded-xl shadow-xl w-full max-w-lg">
          <div className="p-4 border-b flex justify-between items-center bg-gray-50 rounded-t-xl"><h3 className="font-bold text-gray-800 flex items-center gap-2"><MessageSquare size={18} className="text-blue-600"/> Comunicado</h3><button onClick={() => setIsCommModalOpen(false)}><X size={20}/></button></div>
          <div className="p-6">
             {(hasP1 || hasP2) && commType !== 'comercial' && (<div className="mb-4 flex gap-2">{hasP1 && <button onClick={() => setTargetPeriod('p1')} className={`px-2 py-1 text-xs border rounded ${targetPeriod==='p1'?'bg-blue-600 text-white':''}`}>1º Período</button>}{hasP2 && <button onClick={() => setTargetPeriod('p2')} className={`px-2 py-1 text-xs border rounded ${targetPeriod==='p2'?'bg-blue-600 text-white':''}`}>2º Período</button>}</div>)}
             <div className="flex gap-2 mb-4 overflow-x-auto pb-2">{['comercial', 'confirmacao', 'lembrete', 'lideranca'].map(type => (<button key={type} onClick={() => setCommType(type)} className={`px-3 py-1.5 rounded-full text-xs font-bold capitalize ${commType === type ? 'bg-blue-600 text-white' : 'bg-gray-100'}`}>{type}</button>))}</div>
             <div className="bg-gray-50 p-4 rounded-lg border border-gray-200 text-sm font-mono whitespace-pre-wrap h-64 overflow-y-auto">{message}</div>
             <button onClick={() => {navigator.clipboard.writeText(message); alert('Texto copiado!'); setIsCommModalOpen(false);}} className="mt-4 w-full bg-blue-600 text-white py-2 rounded-lg font-bold">Copiar Texto</button>
          </div>
        </div>
      </div>
    );
  };

  const ScheduleModal = () => {
    if (!isScheduleModalOpen) return null;
    const previewReturnDate = scheduleForm.startDate ? getReturnDate(scheduleForm.startDate, scheduleForm.duration) : '-';
    return (
      <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
        <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg">
          <div className="bg-blue-900 px-6 py-4 flex justify-between items-center text-white"><h3>Agendar</h3><button onClick={() => setIsScheduleModalOpen(false)}><X size={20} /></button></div>
          <div className="p-6">
            <div className="mb-6 p-3 bg-gray-50 rounded-lg"><p className="font-bold">{selectedPromoter?.name}</p><p className="text-xs">Saldo: {selectedPromoter.balance} dias</p></div>
            {scheduleError && <div className="mb-4 bg-red-50 text-red-700 p-3 rounded text-xs">{scheduleError}</div>}
            <div className="grid grid-cols-2 gap-4">
              <div><label className="text-xs font-bold">Início</label><input type="date" className="w-full border rounded px-3 py-2" value={scheduleForm.startDate} onChange={(e) => setScheduleForm({...scheduleForm, startDate: e.target.value})}/></div>
              <div><label className="text-xs font-bold">Duração</label><input type="number" className="w-full border rounded px-3 py-2" value={scheduleForm.duration} onChange={(e) => setScheduleForm({...scheduleForm, duration: parseInt(e.target.value)})}/></div>
            </div>
            <div className="mt-4 text-center text-sm">Retorno: <b>{scheduleForm.startDate ? formatDate(previewReturnDate) : '-'}</b></div>
            <button onClick={validateAndSaveSchedule} className="mt-6 w-full py-2.5 bg-blue-600 text-white font-bold rounded-lg">Confirmar</button>
          </div>
        </div>
      </div>
    );
  };

  const AddPromoterModal = () => {
      if (!isAddModalOpen) return null;
      // Form state local simples
      const [formData, setFormData] = useState({ name: '', city: '', regional: '', role: '', admission: '', limitDate: '', balance: 30, status: 'avencer' });
      
      return (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
            <div className="bg-white rounded-xl shadow-xl w-full max-w-2xl">
                <div className="p-4 border-b flex justify-between items-center bg-gray-50 rounded-t-xl"><h3 className="font-bold text-gray-800">Novo Promotor</h3><button onClick={() => setIsAddModalOpen(false)}><X size={20}/></button></div>
                <div className="p-6 grid grid-cols-2 gap-4">
                    <input className="border p-2 rounded" placeholder="Nome Completo" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
                    <input className="border p-2 rounded" placeholder="Cidade" value={formData.city} onChange={e => setFormData({...formData, city: e.target.value})} />
                    <input className="border p-2 rounded" placeholder="Regional" value={formData.regional} onChange={e => setFormData({...formData, regional: e.target.value})} />
                    <input className="border p-2 rounded" placeholder="Cargo/Líder" value={formData.role} onChange={e => setFormData({...formData, role: e.target.value})} />
                    <div><label className="text-xs">Admissão</label><input type="date" className="border p-2 rounded w-full" value={formData.admission} onChange={e => setFormData({...formData, admission: e.target.value})} /></div>
                    <div><label className="text-xs">Limite Férias</label><input type="date" className="border p-2 rounded w-full" value={formData.limitDate} onChange={e => setFormData({...formData, limitDate: e.target.value})} /></div>
                    <input type="number" className="border p-2 rounded" placeholder="Saldo Dias" value={formData.balance} onChange={e => setFormData({...formData, balance: parseInt(e.target.value)})} />
                    <button onClick={() => handleAddNew(formData)} className="col-span-2 bg-blue-600 text-white py-2 rounded font-bold">Salvar Cadastro</button>
                </div>
            </div>
        </div>
      );
  };

  // --- RENDER DATABASE VIEW ---
  const renderDatabase = () => (
    <div className="flex-1 flex flex-col h-full overflow-hidden">
        <div className="bg-white border-b p-6 flex justify-between items-center">
            <div><h1 className="text-2xl font-bold text-gray-800">Base de Dados</h1><p className="text-gray-500 text-sm">Cadastro mestre de promotores.</p></div>
            <div className="flex gap-2">
                <button onClick={() => setIsAddModalOpen(true)} className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg text-sm font-bold"><UserPlus size={16}/> Novo</button>
                <button className="flex items-center gap-2 px-4 py-2 bg-white border rounded-lg text-gray-700 hover:bg-gray-50 text-sm"><Upload size={16}/> Importar CSV</button>
                <button onClick={handleExportBaseCSV} className="flex items-center gap-2 px-4 py-2 bg-white border rounded-lg text-gray-700 hover:bg-gray-50 text-sm"><Download size={16}/> Exportar Base</button>
            </div>
        </div>
        <div className="flex-1 overflow-auto p-6 bg-gray-50">
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
                <table className="w-full text-left">
                    <thead className="bg-gray-50 border-b">
                        <tr>
                            {['Cód', 'Nome', 'Cidade', 'Regional', 'Cargo', 'Admissão', 'Limite', 'Saldo', 'Ações'].map(h => <th key={h} className="px-4 py-3 text-xs font-bold text-gray-500 uppercase">{h}</th>)}
                        </tr>
                    </thead>
                    <tbody className="divide-y">
                        {promoters.map(p => (
                            <tr key={p.id} className="hover:bg-gray-50">
                                <td className="px-4 py-3 text-xs text-gray-500">{p.id}</td>
                                <td className="px-4 py-3">
                                    {editingPromoterId === p.id ? <input className="border rounded px-1 w-full" value={editFormData.name} onChange={e => setEditFormData({...editFormData, name: e.target.value})} /> : <span className="text-sm font-bold text-gray-700">{p.name}</span>}
                                </td>
                                <td className="px-4 py-3 text-xs">
                                    {editingPromoterId === p.id ? <input className="border rounded px-1 w-full" value={editFormData.city} onChange={e => setEditFormData({...editFormData, city: e.target.value})} /> : p.city}
                                </td>
                                <td className="px-4 py-3 text-xs">
                                    {editingPromoterId === p.id ? <input className="border rounded px-1 w-full" value={editFormData.regional} onChange={e => setEditFormData({...editFormData, regional: e.target.value})} /> : p.regional}
                                </td>
                                <td className="px-4 py-3 text-xs">
                                    {editingPromoterId === p.id ? <input className="border rounded px-1 w-full" value={editFormData.role} onChange={e => setEditFormData({...editFormData, role: e.target.value})} /> : p.role}
                                </td>
                                <td className="px-4 py-3 text-xs text-gray-500">{formatDate(p.admission)}</td>
                                <td className="px-4 py-3 text-xs text-red-600 font-bold">
                                    {editingPromoterId === p.id ? <input type="date" className="border rounded px-1" value={editFormData.limitDate} onChange={e => setEditFormData({...editFormData, limitDate: e.target.value})} /> : formatDate(p.limitDate)}
                                </td>
                                <td className="px-4 py-3 text-xs font-bold text-center bg-blue-50 text-blue-700 rounded">
                                    {editingPromoterId === p.id ? <input type="number" className="border rounded px-1 w-12 text-center" value={editFormData.balance} onChange={e => setEditFormData({...editFormData, balance: parseInt(e.target.value)})} /> : p.balance}
                                </td>
                                <td className="px-4 py-3 flex gap-2">
                                    {editingPromoterId === p.id ? (
                                        <button onClick={handleSaveEdit} className="text-green-600 hover:bg-green-50 p-1 rounded"><Save size={16}/></button>
                                    ) : (
                                        <button onClick={() => handleStartEdit(p)} className="text-blue-600 hover:bg-blue-50 p-1 rounded"><Edit2 size={16}/></button>
                                    )}
                                    <button onClick={() => handleDeletePromoter(p.id)} className="text-red-600 hover:bg-red-50 p-1 rounded"><Trash2 size={16}/></button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    </div>
  );

  // --- VIEWS EXISTING ---
  const renderDashboard = () => (
    <div className="p-8 max-w-7xl mx-auto">
      <div className="mb-8"><h1 className="text-2xl font-bold text-gray-900">Visão Geral</h1></div>
      <div className="grid grid-cols-3 gap-6 mb-8">
        <div className="bg-white p-6 rounded-xl border-l-4 border-red-500 shadow-sm"><div><p className="text-xs font-bold text-gray-500">Vencidos</p><p className="text-3xl font-bold">{kpis.vencidos}</p></div></div>
        <div className="bg-white p-6 rounded-xl border-l-4 border-yellow-500 shadow-sm"><div><p className="text-xs font-bold text-gray-500">Negociação</p><p className="text-3xl font-bold">{kpis.negociacao}</p></div></div>
        <div className="bg-white p-6 rounded-xl border-l-4 border-green-500 shadow-sm"><div><p className="text-xs font-bold text-gray-500">Confirmados</p><p className="text-3xl font-bold">{kpis.confirmados}</p></div></div>
      </div>
      <div className="grid grid-cols-2 gap-8">
        <div className="bg-white p-6 rounded-xl shadow-sm"><h3 className="font-bold mb-4 flex items-center gap-2"><Map size={18} className="text-blue-500"/> Regional</h3><div className="space-y-4">{statsByRegional.map(([reg, d]) => <div key={reg} className="flex justify-between border-b pb-2"><span className="text-sm">{reg}</span><span className="text-xs bg-gray-100 px-2 rounded">{d.total}</span></div>)}</div></div>
        <div className="bg-white p-6 rounded-xl shadow-sm"><h3 className="font-bold mb-4 flex items-center gap-2"><Briefcase size={18} className="text-purple-500"/> Liderança</h3><div className="space-y-4 max-h-64 overflow-y-auto">{statsByLeader.map(([role, d]) => <div onClick={() => setSelectedLeader(role)} key={role} className="flex justify-between border-b pb-2 cursor-pointer hover:bg-gray-50"><span className="text-sm">{role}</span><div className="flex gap-2">{d.vencido > 0 && <span className="text-[10px] bg-red-100 text-red-600 px-1 rounded">{d.vencido} V</span>}<span className="text-xs bg-gray-100 px-2 rounded">{d.total}</span></div></div>)}</div></div>
      </div>
    </div>
  );

  const renderManagement = () => (
    <div className="flex-1 flex flex-col h-full overflow-hidden">
      <div className="bg-white border-b p-6 flex justify-between items-center">
         <div><h1 className="text-2xl font-bold text-gray-800">Gestão de Férias</h1></div>
         <div className="flex gap-2 relative">
            <input className="pl-2 border rounded" placeholder="Buscar..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)}/>
            <button onClick={() => setShowFilters(!showFilters)} className="px-3 border rounded"><FilterIcon size={16}/></button>
            <button onClick={handleExportCSV} className="px-3 bg-white border rounded flex items-center gap-1 text-sm"><Download size={16}/> Exportar</button>
         </div>
      </div>
      <div className="flex-1 overflow-auto p-6 bg-gray-50">
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
            <table className="w-full text-left">
                <thead className="bg-gray-50 border-b">
                    <tr>{['Promotor', 'Dias Disp.', 'Status', 'Limite', 'Comunicado', 'Ações'].map(h => <th key={h} className="px-6 py-3 text-xs font-bold text-gray-500 uppercase">{h}</th>)}</tr>
                    {showFilters && <tr className="bg-gray-50"><th className="px-6"><input className="w-full text-xs border rounded" placeholder="Filtrar" value={columnFilters.promotor} onChange={e => setColumnFilters({...columnFilters, promotor: e.target.value})} /></th><th></th><th><select className="w-full text-xs border rounded" value={columnFilters.status} onChange={e => setColumnFilters({...columnFilters, status: e.target.value})}><option value="">Todos</option><option value="vencido">Vencido</option><option value="confirmado">Confirmado</option></select></th><th></th><th></th><th></th></tr>}
                </thead>
                <tbody className="divide-y">{filteredPromoters.map(p => (
                    <tr key={p.id} className="hover:bg-blue-50/30">
                        <td className="px-6 py-4"><div className="font-bold text-sm">{p.name}</div><div className="text-xs text-gray-500">{p.city}</div></td>
                        <td className="px-6 py-4 text-center"><span className="bg-blue-100 text-blue-800 text-xs font-bold px-2 py-1 rounded">{p.balance}</span></td>
                        <td className="px-6 py-4"><div className="flex items-center gap-2"><StatusBadge status={p.status} />{(p.status === 'vencido' || p.status === 'negociacao') && <button onClick={() => toggleNegotiationStatus(p)} className="text-gray-400 hover:text-blue-600"><ArrowRightLeft size={14}/></button>}</div></td>
                        <td className="px-6 py-4 text-sm">{formatDate(p.limitDate)}</td>
                        <td className="px-6 py-4"><button onClick={() => handleOpenComm(p)} className="flex items-center gap-1 border px-2 py-1 rounded text-xs hover:bg-gray-50"><MessageSquare size={14}/> Texto</button></td>
                        <td className="px-6 py-4 text-right">{p.balance === 0 ? <button onClick={() => handleDeleteVacation(p.id)} className="text-red-500 hover:bg-red-50 p-1 rounded"><Trash2 size={16}/></button> : <button onClick={() => handleOpenSchedule(p)} className="bg-blue-600 text-white px-3 py-1 rounded text-xs font-bold">Agendar</button>}</td>
                    </tr>
                ))}</tbody>
            </table>
        </div>
      </div>
    </div>
  );

  const renderCalendar = () => (
    <div className="flex-1 flex flex-col h-full overflow-hidden p-8">
        <div className="flex justify-between items-center mb-6"><h1 className="text-2xl font-bold">Calendário</h1><div className="flex items-center gap-4 border rounded px-3 py-1"><button onClick={handlePrevMonth}><ChevronLeft/></button><span className="font-bold text-sm">{monthNames[calendarDate.getMonth()]} {calendarDate.getFullYear()}</span><button onClick={handleNextMonth}><ChevronRight/></button></div></div>
        <div className="bg-white rounded-xl shadow border overflow-hidden flex-1 flex flex-col">
            <div className="grid grid-cols-7 bg-gray-50 border-b">{['DOM', 'SEG', 'TER', 'QUA', 'QUI', 'SEX', 'SÁB'].map(d => <div key={d} className="py-2 text-center text-xs font-bold text-gray-500">{d}</div>)}</div>
            <div className="grid grid-cols-7 flex-1 auto-rows-fr bg-gray-100 gap-px">
                {(() => {
                    const year = calendarDate.getFullYear();
                    const month = calendarDate.getMonth();
                    const daysInMonth = new Date(year, month + 1, 0).getDate();
                    const startDay = new Date(year, month, 1).getDay();
                    const blanks = [...Array(startDay)].map((_, i) => <div key={`b-${i}`} className="bg-white min-h-[80px] bg-gray-50/30"/>);
                    const days = [...Array(daysInMonth)].map((_, i) => {
                        const day = i + 1;
                        const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
                        const active = promoters.filter(p => {
                            const check = (s, d) => { if(!s) return false; const end = addDays(s, d); return dateStr >= s && dateStr < end; };
                            return check(p.period1.start, p.period1.duration) || check(p.period2.start, p.period2.duration);
                        });
                        return <div key={day} className={`bg-white p-2 min-h-[80px] ${active.length > 0 ? 'bg-green-50/20' : ''}`}><span className="text-sm font-bold">{day}</span><div className="mt-1 space-y-1">{active.map(p => <div key={p.id} className="text-[10px] border px-1 rounded bg-green-100 truncate">{p.name.split(' ')[0]}</div>)}</div></div>;
                    });
                    return [...blanks, ...days];
                })()}
            </div>
        </div>
    </div>
  );

  return (
    <div className="flex h-screen bg-gray-100 font-sans text-gray-900">
      <CommunicationModal />
      <ScheduleModal />
      <LeaderDetailsModal />
      <AddPromoterModal />
      <div className="w-64 bg-slate-900 text-slate-300 flex flex-col flex-shrink-0"><div className="h-16 flex items-center px-6 border-b border-slate-800"><LayoutGrid className="text-blue-500 mr-3" /><span className="font-bold text-white text-lg">Junco Hub</span></div><nav className="flex-1 p-4 space-y-2"><button onClick={() => setCurrentView('dashboard')} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium ${currentView === 'dashboard' ? 'bg-blue-600 text-white' : 'hover:bg-slate-800'}`}><LayoutGrid size={20} /> Visão Geral</button><button onClick={() => setCurrentView('management')} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium ${currentView === 'management' ? 'bg-blue-600 text-white' : 'hover:bg-slate-800'}`}><List size={20} /> Gestão de Férias</button><button onClick={() => setCurrentView('database')} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium ${currentView === 'database' ? 'bg-blue-600 text-white' : 'hover:bg-slate-800'}`}><Database size={20} /> Base de Dados</button><button onClick={() => setCurrentView('calendar')} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium ${currentView === 'calendar' ? 'bg-blue-600 text-white' : 'hover:bg-slate-800'}`}><Calendar size={20} /> Calendário</button></nav></div>
      <div className="flex-1 flex flex-col overflow-hidden relative">{currentView === 'dashboard' && renderDashboard()}{currentView === 'management' && renderManagement()}{currentView === 'database' && renderDatabase()}{currentView === 'calendar' && renderCalendar()}</div>
    </div>
  );
}

