import React, { useState } from 'react';
import { UserPlus, Upload, Download, Edit2, Save, Trash2 } from 'lucide-react';
import { Promoter } from '../types';
import { formatDate } from '../utils';
import { AddPromoterModal } from '../components/Modals';

interface DatabaseViewProps {
  promoters: Promoter[];
  setPromoters: React.Dispatch<React.SetStateAction<Promoter[]>>;
}

export const DatabaseView: React.FC<DatabaseViewProps> = ({ promoters, setPromoters }) => {
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [editingPromoterId, setEditingPromoterId] = useState<number | null>(null);
  const [editFormData, setEditFormData] = useState<Partial<Promoter>>({});

  const handleAddNew = (newData: Omit<Promoter, 'id' | 'period1' | 'period2'>) => {
    const newId = promoters.length > 0 ? Math.max(...promoters.map(p => p.id)) + 1 : 1;
    const newPromoter: Promoter = {
        id: newId,
        ...newData,
        period1: { start: null, duration: 0 },
        period2: { start: null, duration: 0 }
    };
    setPromoters([...promoters, newPromoter]);
    setIsAddModalOpen(false);
  };

  const handleDeletePromoter = (id: number) => {
    if(window.confirm("Tem certeza que deseja excluir este promotor da base?")){
        setPromoters(promoters.filter(p => p.id !== id));
    }
  };

  const handleStartEdit = (promoter: Promoter) => { 
      setEditingPromoterId(promoter.id); 
      setEditFormData({ ...promoter }); 
  };

  const handleSaveEdit = () => { 
      setPromoters(promoters.map(p => p.id === editingPromoterId ? { ...p, ...editFormData } : p)); 
      setEditingPromoterId(null); 
  };

  const handleExportBaseCSV = () => {
    const header = ["ID", "Nome", "Cidade", "Regional", "Cargo", "Admissão", "Data Limite", "Saldo Dias", "Status"];
    const rows = promoters.map(p => [
        p.id, p.name, p.city, p.regional, p.role, formatDate(p.admission), formatDate(p.limitDate), p.balance, p.status
    ]);
    if (rows.length === 0) { alert("Base de dados vazia."); return; }
    const csvContent = "\uFEFF" + [header.join(";"), ...rows.map(row => row.map(item => `"${item}"`).join(";"))].join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", "Base_Completa_Promotores.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="flex-1 flex flex-col h-full overflow-hidden animate-fadeIn">
        <AddPromoterModal isOpen={isAddModalOpen} onClose={() => setIsAddModalOpen(false)} onSave={handleAddNew} />

        <div className="bg-white border-b p-6 flex justify-between items-center shadow-sm">
            <div>
                <h1 className="text-2xl font-bold text-gray-800">Base de Dados</h1>
                <p className="text-gray-500 text-sm">Cadastro mestre de promotores e edição de registros.</p>
            </div>
            <div className="flex gap-2">
                <button onClick={() => setIsAddModalOpen(true)} className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg text-sm font-bold hover:bg-blue-700 transition-colors shadow-sm">
                    <UserPlus size={16}/> Novo
                </button>
                <button className="flex items-center gap-2 px-4 py-2 bg-white border rounded-lg text-gray-700 hover:bg-gray-50 text-sm transition-colors">
                    <Upload size={16}/> Importar CSV
                </button>
                <button onClick={handleExportBaseCSV} className="flex items-center gap-2 px-4 py-2 bg-white border rounded-lg text-gray-700 hover:bg-gray-50 text-sm transition-colors">
                    <Download size={16}/> Exportar Base
                </button>
            </div>
        </div>

        <div className="flex-1 overflow-auto p-6 bg-gray-50">
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
                <table className="w-full text-left">
                    <thead className="bg-gray-50 border-b">
                        <tr>
                            {['Cód', 'Nome', 'Cidade', 'Regional', 'Cargo', 'Admissão', 'Limite', 'Saldo', 'Ações'].map(h => (
                                <th key={h} className="px-4 py-3 text-xs font-bold text-gray-500 uppercase tracking-wider">{h}</th>
                            ))}
                        </tr>
                    </thead>
                    <tbody className="divide-y">
                        {promoters.map(p => (
                            <tr key={p.id} className="hover:bg-gray-50 transition-colors">
                                <td className="px-4 py-3 text-xs text-gray-500 font-mono">{p.id}</td>
                                <td className="px-4 py-3">
                                    {editingPromoterId === p.id ? <input className="border rounded px-2 py-1 w-full text-sm" value={editFormData.name} onChange={e => setEditFormData({...editFormData, name: e.target.value})} /> : <span className="text-sm font-bold text-gray-700">{p.name}</span>}
                                </td>
                                <td className="px-4 py-3 text-xs">
                                    {editingPromoterId === p.id ? <input className="border rounded px-2 py-1 w-full text-xs" value={editFormData.city} onChange={e => setEditFormData({...editFormData, city: e.target.value})} /> : p.city}
                                </td>
                                <td className="px-4 py-3 text-xs">
                                    {editingPromoterId === p.id ? <input className="border rounded px-2 py-1 w-full text-xs" value={editFormData.regional} onChange={e => setEditFormData({...editFormData, regional: e.target.value})} /> : p.regional}
                                </td>
                                <td className="px-4 py-3 text-xs">
                                    {editingPromoterId === p.id ? <input className="border rounded px-2 py-1 w-full text-xs" value={editFormData.role} onChange={e => setEditFormData({...editFormData, role: e.target.value})} /> : p.role}
                                </td>
                                <td className="px-4 py-3 text-xs text-gray-500">{formatDate(p.admission)}</td>
                                <td className="px-4 py-3 text-xs text-red-600 font-bold tabular-nums">
                                    {editingPromoterId === p.id ? <input type="date" className="border rounded px-1" value={editFormData.limitDate} onChange={e => setEditFormData({...editFormData, limitDate: e.target.value})} /> : formatDate(p.limitDate)}
                                </td>
                                <td className="px-4 py-3 text-xs font-bold text-center">
                                    {editingPromoterId === p.id ? (
                                        <input type="number" className="border rounded px-1 w-12 text-center" value={editFormData.balance} onChange={e => setEditFormData({...editFormData, balance: parseInt(e.target.value)})} />
                                    ) : (
                                        <span className="bg-blue-50 text-blue-700 px-2 py-1 rounded">{p.balance}</span>
                                    )}
                                </td>
                                <td className="px-4 py-3 flex gap-2">
                                    {editingPromoterId === p.id ? (
                                        <button onClick={handleSaveEdit} className="text-green-600 hover:bg-green-50 p-1.5 rounded transition-colors"><Save size={16}/></button>
                                    ) : (
                                        <button onClick={() => handleStartEdit(p)} className="text-blue-600 hover:bg-blue-50 p-1.5 rounded transition-colors"><Edit2 size={16}/></button>
                                    )}
                                    <button onClick={() => handleDeletePromoter(p.id)} className="text-red-600 hover:bg-red-50 p-1.5 rounded transition-colors"><Trash2 size={16}/></button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    </div>
  );
};

import React, { useState } from 'react';
import { ChevronLeft, ChevronRight } from 'lucide-react';
import { Promoter } from '../types';
import { addDays } from '../utils';

interface CalendarViewProps {
  promoters: Promoter[];
}

export const CalendarView: React.FC<CalendarViewProps> = ({ promoters }) => {
  const [calendarDate, setCalendarDate] = useState(new Date('2026-01-01T12:00:00'));

  const handlePrevMonth = () => {
    setCalendarDate(new Date(calendarDate.getFullYear(), calendarDate.getMonth() - 1, 1));
  };

  const handleNextMonth = () => {
    setCalendarDate(new Date(calendarDate.getFullYear(), calendarDate.getMonth() + 1, 1));
  };

  const monthNames = ["Janeiro", "Fevereiro", "Março", "Abril", "Maio", "Junho", "Julho", "Agosto", "Setembro", "Outubro", "Novembro", "Dezembro"];

  const renderDays = () => {
    const year = calendarDate.getFullYear();
    const month = calendarDate.getMonth();
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    const startDay = new Date(year, month, 1).getDay();

    const blanks = [...Array(startDay)].map((_, i) => <div key={`b-${i}`} className="bg-gray-50/50 min-h-[100px] border-r border-b border-gray-100"/>);

    const days = [...Array(daysInMonth)].map((_, i) => {
        const day = i + 1;
        const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;

        const active = promoters.filter(p => {
            const check = (s: string | null, d: number) => { 
                if(!s) return false; 
                const end = addDays(s, d); 
                return dateStr >= s && dateStr < end; 
            };
            return check(p.period1.start, p.period1.duration) || check(p.period2.start, p.period2.duration);
        });

        return (
            <div key={day} className={`bg-white p-2 min-h-[100px] border-r border-b border-gray-100 transition-colors hover:bg-gray-50 ${active.length > 0 ? 'bg-green-50/30' : ''}`}>
                <span className={`text-sm font-bold ${active.length > 0 ? 'text-green-700' : 'text-gray-700'}`}>{day}</span>
                <div className="mt-2 space-y-1 overflow-hidden">
                    {active.map(p => (
                        <div key={p.id} className="text-[10px] border border-green-200 px-1.5 py-0.5 rounded bg-green-100 text-green-800 truncate shadow-sm">
                            {p.name.split(' ')[0]}
                        </div>
                    ))}
                </div>
            </div>
        );
    });

    return [...blanks, ...days];
  };

  return (
    <div className="flex-1 flex flex-col h-full overflow-hidden p-8 animate-fadeIn">
        <div className="flex justify-between items-center mb-6">
            <h1 className="text-2xl font-bold text-gray-900">Calendário</h1>
            <div className="flex items-center gap-4 bg-white border rounded-xl px-4 py-2 shadow-sm">
                <button onClick={handlePrevMonth} className="p-1 hover:bg-gray-100 rounded-full transition-colors"><ChevronLeft size={20}/></button>
                <span className="font-bold text-gray-800 w-32 text-center">{monthNames[calendarDate.getMonth()]} {calendarDate.getFullYear()}</span>
                <button onClick={handleNextMonth} className="p-1 hover:bg-gray-100 rounded-full transition-colors"><ChevronRight size={20}/></button>
            </div>
        </div>

        <div className="bg-white rounded-xl shadow-lg border border-gray-200 overflow-hidden flex-1 flex flex-col">
            <div className="grid grid-cols-7 bg-gray-50 border-b border-gray-200">
                {['DOM', 'SEG', 'TER', 'QUA', 'QUI', 'SEX', 'SÁB'].map(d => (
                    <div key={d} className="py-3 text-center text-xs font-bold text-gray-500 tracking-wider">{d}</div>
                ))}
            </div>
            <div className="grid grid-cols-7 flex-1 auto-rows-fr bg-gray-100 gap-px overflow-y-auto custom-scrollbar">
                {renderDays()}
            </div>
        </div>
    </div>
  );
};

import React, { useState } from 'react';
import { INITIAL_DB, ViewState, Promoter } from './types';
import { Sidebar } from './components/Sidebar';
import { DashboardView } from './views/DashboardView';
import { ManagementView } from './views/ManagementView';
import { DatabaseView } from './views/DatabaseView';
import { CalendarView } from './views/CalendarView';

function App() {
  const [currentView, setCurrentView] = useState<ViewState>('dashboard');
  const [promoters, setPromoters] = useState<Promoter[]>(INITIAL_DB);

  const renderContent = () => {
    switch (currentView) {
      case 'dashboard':
        return <DashboardView promoters={promoters} />;
      case 'management':
        return <ManagementView promoters={promoters} setPromoters={setPromoters} />;
      case 'database':
        return <DatabaseView promoters={promoters} setPromoters={setPromoters} />;
      case 'calendar':
        return <CalendarView promoters={promoters} />;
      default:
        return <DashboardView promoters={promoters} />;
    }
  };

  return (
    <div className="flex h-screen bg-gray-100 font-sans text-gray-900">
      <Sidebar currentView={currentView} setCurrentView={setCurrentView} />
      <div className="flex-1 flex flex-col overflow-hidden relative">
        {renderContent()}
      </div>
    </div>
  );
}

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

