// --- Communication Modal ---
interface CommunicationModalProps {
  isOpen: boolean;
  onClose: () => void;
  promoter: Promoter | null;
}

export const CommunicationModal: React.FC<CommunicationModalProps> = ({ isOpen, onClose, promoter }) => {
  const [commType, setCommType] = useState('confirmacao');
  const [targetPeriod, setTargetPeriod] = useState('both');

  const hasP1 = promoter?.period1?.start ? true : false;
  const hasP2 = promoter?.period2?.start ? true : false;
  const pStatus = promoter?.status;

  useEffect(() => {
    if (!isOpen || !promoter) return;

    if (hasP1 && hasP2) setTargetPeriod('both');
    else if (hasP1) setTargetPeriod('p1');
    else if (hasP2) setTargetPeriod('p2');
    else setTargetPeriod('none');

    if (pStatus === 'vencido' || pStatus === 'negociacao') setCommType('comercial');
    else setCommType('confirmacao');
  }, [isOpen, promoter, hasP1, hasP2, pStatus]);

  if (!isOpen || !promoter) return null;

  const generateMessage = () => {
    if (!promoter) return '';
    const p1 = promoter.period1;
    const p2 = promoter.period2;
    const includeP1 = (targetPeriod === 'p1' || targetPeriod === 'both') && !!p1.start;
    const includeP2 = (targetPeriod === 'p2' || targetPeriod === 'both') && !!p2.start;

    if (commType === 'comercial') {
        return `Bom dia time, tudo bem?\n\nEstamos com um promotor que está com férias vencidas e precisamos marcá-las. Segue abaixo o promotor:\n\n*${promoter.name}*\n${promoter.city}\n\nLembrando que ele goza das férias apenas em períodos de 15 dias, sendo necessário marcar apenas *UM* período por conta das férias coletivas.`;
    }
    if (commType === 'confirmacao') {
        let text = "";
        if (includeP1) text += `*Primeiro Período:*\n*Início:* ${formatDate(p1.start)}\n*Término:* ${formatDate(addDays(p1.start!, p1.duration - 1))}\n*Retorno:* _${formatDate(getReturnDate(p1.start!, p1.duration))}_\n\n`;
        if (includeP2) text += `*Segundo Período:*\n*Início:* ${formatDate(p2.start)}\n*Término:* ${formatDate(addDays(p2.start!, p2.duration - 1))}\n*Retorno:* _${formatDate(getReturnDate(p2.start!, p2.duration))}_`;
        if (!text) return "Selecione um período.";
        return `🤖*MENSAGEM AUTOMÁTICA*🤖\n\nCaro(a) colaborador(a), seus períodos de férias foram agendados com sucesso para as seguintes datas:\n\n${text}\nPara acompanhar, basta acessar o aplicativo *_Pessoas+_*`;
    }
    const activeStart = includeP1 ? p1.start : (includeP2 ? p2.start : null);
    const activeDur = includeP1 ? p1.duration : (includeP2 ? p2.duration : 0);
    if (!activeStart) return "Selecione um período agendado.";

    if (commType === 'lembrete') return `Prezado,\n\nGostaríamos de informar que suas férias se iniciam no dia ${formatDate(activeStart)} e seu retorno às atividades será no dia ${formatDate(getReturnDate(activeStart, activeDur))}.\n\nDesejamos boas férias!`;
    if (commType === 'lideranca') return `Bom dia time, tudo bem?\n\nGostaríamos de informar que o promotor *${promoter.name}* (${promoter.city}) entrará em férias em breve.\n\n*Início:* ${formatDate(activeStart)}\n*Retorno:* ${formatDate(getReturnDate(activeStart, activeDur))}\n\nFavor se atentarem a este período.`;
    return '';
  };

  const message = generateMessage();

  return (
    <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 backdrop-blur-sm animate-fadeIn">
      <div className="bg-white rounded-xl shadow-xl w-full max-w-lg">
        <div className="p-4 border-b flex justify-between items-center bg-gray-50 rounded-t-xl">
          <h3 className="font-bold text-gray-800 flex items-center gap-2"><MessageSquare size={18} className="text-blue-600"/> Comunicado</h3>
          <button onClick={onClose}><X size={20}/></button>
        </div>
        <div className="p-6">
           {(hasP1 || hasP2) && commType !== 'comercial' && (
             <div className="mb-4 flex gap-2">
               {hasP1 && <button onClick={() => setTargetPeriod('p1')} className={`px-3 py-1 text-xs border rounded transition-colors ${targetPeriod==='p1'?'bg-blue-600 text-white shadow-sm':'hover:bg-gray-50'}`}>1º Período</button>}
               {hasP2 && <button onClick={() => setTargetPeriod('p2')} className={`px-3 py-1 text-xs border rounded transition-colors ${targetPeriod==='p2'?'bg-blue-600 text-white shadow-sm':'hover:bg-gray-50'}`}>2º Período</button>}
               {hasP1 && hasP2 && <button onClick={() => setTargetPeriod('both')} className={`px-3 py-1 text-xs border rounded transition-colors ${targetPeriod==='both'?'bg-blue-600 text-white shadow-sm':'hover:bg-gray-50'}`}>Ambos</button>}
             </div>
           )}
           <div className="flex gap-2 mb-4 overflow-x-auto pb-2 custom-scrollbar">
             {['comercial', 'confirmacao', 'lembrete', 'lideranca'].map(type => (
               <button key={type} onClick={() => setCommType(type)} className={`px-3 py-1.5 rounded-full text-xs font-bold capitalize transition-colors whitespace-nowrap ${commType === type ? 'bg-blue-600 text-white shadow-md' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'}`}>{type}</button>
             ))}
           </div>
           <div className="bg-gray-50 p-4 rounded-lg border border-gray-200 text-sm font-mono whitespace-pre-wrap h-64 overflow-y-auto custom-scrollbar text-gray-700">
             {message}
           </div>
           <button 
            onClick={() => {navigator.clipboard.writeText(message); alert('Texto copiado!'); onClose();}} 
            className="mt-4 w-full bg-blue-600 text-white py-2 rounded-lg font-bold hover:bg-blue-700 transition-colors shadow-sm"
           >
             Copiar Texto
           </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { ChevronLeft, ChevronRight } from 'lucide-react';
import { Promoter } from '../types';
import { addDays } from '../utils';

interface CalendarViewProps {
  promoters: Promoter[];
}

export const CalendarView: React.FC<CalendarViewProps> = ({ promoters }) => {
  const [calendarDate, setCalendarDate] = useState(new Date()); // Start at current date for better UX

  const handlePrevMonth = () => {
    setCalendarDate(new Date(calendarDate.getFullYear(), calendarDate.getMonth() - 1, 1));
  };

  const handleNextMonth = () => {
    setCalendarDate(new Date(calendarDate.getFullYear(), calendarDate.getMonth() + 1, 1));
  };

  const monthNames = ["Janeiro", "Fevereiro", "Março", "Abril", "Maio", "Junho", "Julho", "Agosto", "Setembro", "Outubro", "Novembro", "Dezembro"];

  const renderDays = () => {
    const year = calendarDate.getFullYear();
    const month = calendarDate.getMonth();
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    const startDay = new Date(year, month, 1).getDay();

    const blanks = [...Array(startDay)].map((_, i) => <div key={`b-${i}`} className="bg-gray-50/50 min-h-[100px] border-r border-b border-gray-100"/>);

    const days = [...Array(daysInMonth)].map((_, i) => {
        const day = i + 1;
        const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;

        const active = promoters.filter(p => {
            const check = (s: string | null, d: number) => { 
                if(!s) return false; 
                const end = addDays(s, d); 
                return dateStr >= s && dateStr < end; 
            };
            return check(p.period1.start, p.period1.duration) || check(p.period2.start, p.period2.duration);
        });

        const hasActive = active.length > 0;

        return (
            <div key={day} className={`bg-white p-2 min-h-[100px] border-r border-b border-gray-100 transition-colors hover:bg-gray-50 ${hasActive ? 'bg-orange-50' : ''}`}>
                <span className={`text-sm font-bold ${hasActive ? 'text-orange-700' : 'text-gray-700'}`}>{day}</span>
                <div className="mt-2 space-y-1 overflow-hidden">
                    {active.map(p => (
                        <div key={p.id} className="text-[10px] border border-orange-200 px-1.5 py-0.5 rounded bg-orange-100 text-orange-900 truncate shadow-sm font-medium">
                            {p.name.split(' ')[0]}
                        </div>
                    ))}
                </div>
            </div>
        );
    });

    return [...blanks, ...days];
  };

  return (
    <div className="flex-1 flex flex-col h-full overflow-hidden p-8 animate-fadeIn">
        <div className="flex justify-between items-center mb-6">
            <h1 className="text-2xl font-bold text-gray-900">Calendário</h1>
            <div className="flex items-center gap-4 bg-white border rounded-xl px-4 py-2 shadow-sm">
                <button onClick={handlePrevMonth} className="p-1 hover:bg-gray-100 rounded-full transition-colors"><ChevronLeft size={20}/></button>
                <span className="font-bold text-gray-800 w-32 text-center">{monthNames[calendarDate.getMonth()]} {calendarDate.getFullYear()}</span>
                <button onClick={handleNextMonth} className="p-1 hover:bg-gray-100 rounded-full transition-colors"><ChevronRight size={20}/></button>
            </div>
        </div>

        <div className="bg-white rounded-xl shadow-lg border border-gray-200 overflow-hidden flex-1 flex flex-col">
            <div className="grid grid-cols-7 bg-gray-50 border-b border-gray-200">
                {['DOM', 'SEG', 'TER', 'QUA', 'QUI', 'SEX', 'SÁB'].map(d => (
                    <div key={d} className="py-3 text-center text-xs font-bold text-gray-500 tracking-wider">{d}</div>
                ))}
            </div>
            <div className="grid grid-cols-7 flex-1 auto-rows-fr bg-gray-100 gap-px overflow-y-auto custom-scrollbar">
                {renderDays()}
            </div>
        </div>
    </div>
  );
};

import React, { useMemo, useState } from 'react';
import { Map, Briefcase, Clock, AlertTriangle, Calendar } from 'lucide-react';
import { Promoter } from '../types';
import { LeaderDetailsModal } from '../components/Modals';
import { formatDate } from '../utils';

interface DashboardViewProps {
  promoters: Promoter[];
}

export const DashboardView: React.FC<DashboardViewProps> = ({ promoters }) => {
  const [selectedLeader, setSelectedLeader] = useState<string | null>(null);

  const kpis = {
    vencidos: promoters.filter(p => p.status === 'vencido').length,
    negociacao: promoters.filter(p => p.status === 'negociacao').length,
    confirmados: promoters.filter(p => p.status === 'confirmado').length,
  };

  // --- Logic for Upcoming Vacations (5 Days) ---
  const upcomingVacations = useMemo(() => {
    const today = new Date();
    today.setHours(0, 0, 0, 0);

    const results: { promoter: Promoter, startDate: string, daysLeft: number }[] = [];

    promoters.forEach(p => {
        const checkPeriod = (startStr: string | null) => {
            if (!startStr) return;
            const start = new Date(startStr + 'T12:00:00');
            start.setHours(0, 0, 0, 0);

            // Calculate difference in days
            const diffTime = start.getTime() - today.getTime();
            const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

            if (diffDays >= 0 && diffDays <= 5) {
                results.push({
                    promoter: p,
                    startDate: startStr,
                    daysLeft: diffDays
                });
            }
        };

        checkPeriod(p.period1.start);
        checkPeriod(p.period2.start);
    });

    return results.sort((a, b) => a.daysLeft - b.daysLeft);
  }, [promoters]);

  const statsByRegional = useMemo(() => {
    const acc: Record<string, { total: number; }> = {};
    promoters.forEach(p => {
        const reg = p.regional || 'OUTROS';
        if (!acc[reg]) acc[reg] = { total: 0 };
        acc[reg].total++;
    });
    return Object.entries(acc);
  }, [promoters]);

  const statsByLeader = useMemo(() => {
    const acc: Record<string, { total: number; vencido: number; }> = {};
    promoters.forEach(p => {
        const role = p.role || 'SEM LÍDER';
        if (!acc[role]) acc[role] = { total: 0, vencido: 0 };
        acc[role].total++;
        if (p.status === 'vencido') acc[role].vencido++;
    });
    return Object.entries(acc);
  }, [promoters]);

  return (
    <div className="p-8 max-w-7xl mx-auto h-full overflow-y-auto custom-scrollbar">
      <LeaderDetailsModal selectedLeader={selectedLeader} onClose={() => setSelectedLeader(null)} promoters={promoters} />

      <div className="mb-8">
        <h1 className="text-3xl font-bold text-gray-900 tracking-tight">Visão Geral</h1>
        <p className="text-gray-500 mt-1">Acompanhe os principais indicadores de férias.</p>
      </div>

      {/* --- New Alert Section --- */}
      {upcomingVacations.length > 0 && (
        <div className="mb-8 bg-orange-50 border border-orange-200 rounded-xl p-6 shadow-sm animate-fadeIn">
            <h3 className="font-bold text-orange-900 flex items-center gap-2 mb-4">
                <Clock className="text-orange-600" size={20} />
                Início Próximo (5 dias)
                <span className="bg-orange-200 text-orange-800 text-xs px-2 py-0.5 rounded-full">{upcomingVacations.length}</span>
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {upcomingVacations.map((item, idx) => (
                    <div key={idx} className="bg-white p-3 rounded-lg border border-orange-100 flex justify-between items-center shadow-sm">
                        <div>
                            <div className="font-bold text-sm text-gray-800">{item.promoter.name}</div>
                            <div className="text-xs text-gray-500">{item.promoter.city}</div>
                        </div>
                        <div className="text-right">
                            <div className="text-xs font-bold text-orange-600 bg-orange-50 px-2 py-1 rounded">
                                {item.daysLeft === 0 ? 'Hoje' : `Faltam ${item.daysLeft} dias`}
                            </div>
                            <div className="text-[10px] text-gray-400 mt-1">{formatDate(item.startDate)}</div>
                        </div>
                    </div>
                ))}
            </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
        <div className="bg-white p-6 rounded-xl border-l-4 border-red-500 shadow-sm hover:shadow-md transition-shadow">
          <div><p className="text-xs font-bold text-gray-500 uppercase tracking-wider">Vencidos</p><p className="text-4xl font-bold text-gray-800 mt-2">{kpis.vencidos}</p></div>
        </div>
        <div className="bg-white p-6 rounded-xl border-l-4 border-yellow-500 shadow-sm hover:shadow-md transition-shadow">
          <div><p className="text-xs font-bold text-gray-500 uppercase tracking-wider">Em Negociação</p><p className="text-4xl font-bold text-gray-800 mt-2">{kpis.negociacao}</p></div>
        </div>
        <div className="bg-white p-6 rounded-xl border-l-4 border-green-500 shadow-sm hover:shadow-md transition-shadow">
          <div><p className="text-xs font-bold text-gray-500 uppercase tracking-wider">Confirmados</p><p className="text-4xl font-bold text-gray-800 mt-2">{kpis.confirmados}</p></div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <h3 className="font-bold mb-6 flex items-center gap-2 text-lg text-gray-800">
            <div className="bg-blue-100 p-2 rounded-lg"><Map size={20} className="text-blue-600"/></div>
            Regional
          </h3>
          <div className="space-y-4">
            {statsByRegional.map(([reg, d]) => (
              <div key={reg} className="flex justify-between items-center border-b border-gray-100 pb-3 last:border-0">
                <span className="text-sm font-medium text-gray-700">{reg}</span>
                <span className="text-xs font-bold bg-gray-100 text-gray-600 px-3 py-1 rounded-full">{d.total}</span>
              </div>
            ))}
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <h3 className="font-bold mb-6 flex items-center gap-2 text-lg text-gray-800">
            <div className="bg-purple-100 p-2 rounded-lg"><Briefcase size={20} className="text-purple-600"/></div>
            Liderança
          </h3>
          <div className="space-y-3 max-h-80 overflow-y-auto custom-scrollbar pr-2">
            {statsByLeader.map(([role, d]) => (
              <div 
                onClick={() => setSelectedLeader(role)} 
                key={role} 
                className="flex justify-between items-center p-3 rounded-lg cursor-pointer hover:bg-gray-50 transition-colors border border-transparent hover:border-gray-100"
              >
                <span className="text-sm font-medium text-gray-700">{role}</span>
                <div className="flex gap-2">
                  {d.vencido > 0 && <span className="text-[10px] font-bold bg-red-100 text-red-600 px-2 py-1 rounded-md">{d.vencido} V</span>}
                  <span className="text-xs font-bold bg-gray-100 text-gray-600 px-3 py-1 rounded-full">{d.total}</span>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export type PromoterStatus = 'confirmado' | 'negociacao' | 'vencido' | 'avencer';

export interface Period {
  start: string | null;
  duration: number;
}

export interface Promoter {
  id: number;
  name: string;
  city: string;
  role: string;
  regional: string;
  admission: string;
  limitDate: string;
  balance: number;
  status: PromoterStatus;
  period1: Period;
  period2: Period;
}

export type ViewState = 'dashboard' | 'management' | 'database' | 'calendar';

export interface ColumnFilters {
  promotor: string;
  balance: string;
  status: string;
  limitDate: string;
}

// Helper to get a date string for N days from now
const getFutureDate = (days: number) => {
    const date = new Date();
    date.setDate(date.getDate() + days);
    return date.toISOString().split('T')[0];
};

